data.command:
set -euo pipefail

log() { printf '[mysql-group-replication-ha] %s\n' "$*"; }
detect_current_ip() {
  for candidate in $(hostname -I 2>/dev/null); do
    case " 10.0.1.11 10.0.1.12 10.0.1.13 " in
      *" $candidate "*) printf '%s' "$candidate"; return 0 ;;
    esac
  done
  ip -o -4 addr show scope global 2>/dev/null | awk '{split($4,a,"/"); print a[1]; exit}'
}
CURRENT_IP="${OCTASTACK_NODE_IP:-$(detect_current_ip)}"
NODE_NAME="$(hostname -s)"
NODE_ROLE="unknown"
NODE_INDEX=0
case "$CURRENT_IP" in
  10.0.1.11) NODE_NAME='mysql-01'; NODE_ROLE='mysql'; NODE_INDEX=1 ;;
  10.0.1.12) NODE_NAME='mysql-02'; NODE_ROLE='mysql'; NODE_INDEX=2 ;;
  10.0.1.13) NODE_NAME='mysql-03'; NODE_ROLE='mysql'; NODE_INDEX=3 ;;
esac
if [ "$NODE_ROLE" = "unknown" ]; then
  log "unable to match current host IP ($CURRENT_IP) to the generated topology"
  exit 1
fi
log "running on $NODE_NAME ($CURRENT_IP, role=$NODE_ROLE)"

container_ready=0
for attempt in $(seq 1 60); do
  if docker exec octastack-mysql sh -lc "mysqladmin ping -uroot -pchange-me" >/dev/null 2>&1; then
    container_ready=1
    break
  fi
  sleep 5
done
if [ "$container_ready" = "1" ]; then
  log "container octastack-mysql is ready"
else
docker logs octastack-mysql --tail=120 || true
echo "container octastack-mysql did not become ready" >&2
exit 1
fi

if [ "$NODE_INDEX" = "1" ]; then
  docker exec octastack-mysql mysql -uroot -pchange-me <<'SQL'
SET SQL_LOG_BIN=0;
CREATE USER IF NOT EXISTS 'repl'@'%' IDENTIFIED BY 'change-me';
GRANT REPLICATION SLAVE ON *.* TO 'repl'@'%';
GRANT CONNECTION_ADMIN, BACKUP_ADMIN, GROUP_REPLICATION_STREAM ON *.* TO 'repl'@'%';
FLUSH PRIVILEGES;
SET SQL_LOG_BIN=1;
INSTALL PLUGIN group_replication SONAME 'group_replication.so';
SET GLOBAL group_replication_bootstrap_group=ON;
START GROUP_REPLICATION USER='repl', PASSWORD='change-me';
SET GLOBAL group_replication_bootstrap_group=OFF;
SQL
else
  sleep 20
  docker exec octastack-mysql mysql -uroot -pchange-me <<'SQL'
INSTALL PLUGIN group_replication SONAME 'group_replication.so';
START GROUP_REPLICATION USER='repl', PASSWORD='change-me';
SQL
fi
